1	// COR24 APL Interpreter -- Tokenizer
2	// Lexes input line into token array for the parser.
3	
4	#pragma once
5	
6	// Token types
7	#define TOK_EOL     0   // end of line
8	#define TOK_NUM     1   // integer literal (value in tok_val)
9	#define TOK_IDENT   2   // user identifier (uppercase, pos in tok_val)
10	#define TOK_PLUS    3   // +
11	#define TOK_MINUS   4   // - (parser decides monadic vs dyadic)
12	#define TOK_STAR    5   // *
13	#define TOK_SLASH   6   // /
14	#define TOK_LPAREN  7   // (
15	#define TOK_RPAREN  8   // )
16	#define TOK_ASSIGN  9   // <-
17	#define TOK_RES    10   // reserved word (ID in tok_val)
18	#define TOK_QUAD   11   // quad ([] — bare quad for I/O)
19	#define TOK_QLED   12   // qled — LED D2 hardware I/O
20	#define TOK_QSW    13   // qsw — switch S2 hardware I/O (read-only)
21	#define TOK_QSVO   14   // qsvo — shared variable offer (□SVO)
22	#define TOK_LBRAK  15   // [ (bracket index open)
23	#define TOK_RBRAK  16   // ] (bracket index close)
24	#define TOK_GOTO   17   // goto — branch (→)
25	#define TOK_STRING 18   // string literal 'ABC' (pos of first char in tok_val)
26	#define TOK_EQ     19   // =
27	#define TOK_NE     20   // !=
28	#define TOK_LT     21   // <
29	#define TOK_GT     22   // >
30	#define TOK_LE     23   // <=
31	#define TOK_GE     24   // >=
32	#define TOK_CEIL   25   // ceil (max) — internal only, used in reduce nodes
33	#define TOK_FLOOR  26   // floor (min) — internal only, used in reduce nodes
34	
35	// Reserved word IDs
36	#define RES_RHO     0
37	#define RES_IOTA    1
38	#define RES_TAKE    2
39	#define RES_DROP    3
40	#define RES_REV     4
41	#define RES_CAT     5
42	#define RES_AND     6
43	#define RES_OR      7
44	#define RES_NOT     8
45	#define RES_CEIL    9
46	#define RES_FLOOR  10
47	
48	#define TOK_MAX    64   // max tokens per line
49	
50	// Token storage (parallel arrays)
51	int tok_type[TOK_MAX];  // token type
52	int tok_val[TOK_MAX];   // numeric value or reserved word ID
53	int tok_pos[TOK_MAX];   // start position in source line
54	int tok_count;           // number of tokens produced
55	
56	// ---- String helpers ----
57	
58	// Compare a substring of src starting at pos against a NUL-terminated word.
59	// Returns 1 if match, 0 otherwise.
60	int str_match(char *src, int pos, char *word) {
61	    int i = 0;
62	    while (word[i]) {
63	        if (src[pos + i] != word[i]) return 0;
64	        i++;
65	    }
66	    return i;  // return length of match (0 = no match since word is non-empty)
67	}
68	
69	// Check if character is a lowercase letter (a-z)
70	int is_lower(int ch) {
71	    return ch >= 97 && ch <= 122;
72	}
73	
74	// Check if character is an uppercase letter (A-Z)
75	int is_upper(int ch) {
76	    return ch >= 65 && ch <= 90;
77	}
78	
79	// Check if character is a digit (0-9)
80	int is_digit(int ch) {
81	    return ch >= 48 && ch <= 57;
82	}
83	
84	// Check if character is alphanumeric or underscore
85	int is_alnum(int ch) {
86	    return is_lower(ch) || is_upper(ch) || is_digit(ch);
87	}
88	
89	// ---- Reserved word lookup ----
90	// Returns reserved word ID if the lowercase word starting at pos matches,
91	// or -1 if not a reserved word. Sets *end to position past the word.
92	int lookup_reserved(char *src, int pos, int *end) {
93	    int len;
94	
95	    len = str_match(src, pos, "rho");
96	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_RHO; }
97	
98	    len = str_match(src, pos, "iota");
99	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_IOTA; }
100	
101	    len = str_match(src, pos, "take");
102	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_TAKE; }
103	
104	    len = str_match(src, pos, "drop");
105	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_DROP; }
106	
107	    len = str_match(src, pos, "rev");
108	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_REV; }
109	
110	    len = str_match(src, pos, "cat");
111	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_CAT; }
112	
113	    len = str_match(src, pos, "and");
114	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_AND; }
115	
116	    len = str_match(src, pos, "or");
117	    if (len == 2 && !is_alnum(src[pos + 2])) { *end = pos + 2; return RES_OR; }
118	
119	    len = str_match(src, pos, "not");
120	    if (len == 3 && !is_alnum(src[pos + 3])) { *end = pos + 3; return RES_NOT; }
121	
122	    len = str_match(src, pos, "ceil");
123	    if (len == 4 && !is_alnum(src[pos + 4])) { *end = pos + 4; return RES_CEIL; }
124	
125	    len = str_match(src, pos, "floor");
126	    if (len == 5 && !is_alnum(src[pos + 5])) { *end = pos + 5; return RES_FLOOR; }
127	
128	    return -1;
129	}
130	
131	// ---- Tokenizer ----
132	// Tokenize input line into tok_type/tok_val/tok_pos arrays.
133	// Returns number of tokens (also stored in tok_count).
134	// On error, returns -1 (unrecognized character).
135	int tokenize(char *line) {
136	    int i = 0;
137	    int t = 0;
138	
139	    while (line[i] && t < TOK_MAX - 1) {
140	        // Skip whitespace
141	        if (line[i] == 32) {
142	            i++;
143	            continue;
144	        }
145	
146	        // Number: digits, or underscore followed by digit (APL negative)
147	        if (is_digit(line[i]) || (line[i] == 95 && is_digit(line[i + 1]))) {
148	            tok_type[t] = TOK_NUM;
149	            tok_pos[t] = i;
150	            int end;
151	            tok_val[t] = parse_int(line, i, &end);
152	            i = end;
153	            t++;
154	            continue;
155	        }
156	
157	        // Lowercase letter: quad variables, reserved word, or unknown
158	        if (is_lower(line[i])) {
159	            // Check for quad variables first
160	            int len;
161	            len = str_match(line, i, "qled");
162	            if (len == 4 && !is_alnum(line[i + 4])) {
163	                tok_type[t] = TOK_QLED;
164	                tok_pos[t] = i;
165	                tok_val[t] = 0;
166	                t++;
167	                i = i + 4;
168	                continue;
169	            }
170	
171	            len = str_match(line, i, "qsw");
172	            if (len == 3 && !is_alnum(line[i + 3])) {
173	                tok_type[t] = TOK_QSW;
174	                tok_pos[t] = i;
175	                tok_val[t] = 0;
176	                t++;
177	                i = i + 3;
178	                continue;
179	            }
180	
181	            len = str_match(line, i, "qsvo");
182	            if (len == 4 && !is_alnum(line[i + 4])) {
183	                tok_type[t] = TOK_QSVO;
184	                tok_pos[t] = i;
185	                tok_val[t] = 0;
186	                t++;
187	                i = i + 4;
188	                continue;
189	            }
190	
191	            len = str_match(line, i, "goto");
192	            if (len == 4 && !is_alnum(line[i + 4])) {
193	                tok_type[t] = TOK_GOTO;
194	                tok_pos[t] = i;
195	                tok_val[t] = 0;
196	                t++;
197	                i = i + 4;
198	                continue;
199	            }
200	
201	            int end;
202	            int res = lookup_reserved(line, i, &end);
203	            if (res >= 0) {
204	                tok_type[t] = TOK_RES;
205	                tok_val[t] = res;
206	                tok_pos[t] = i;
207	                i = end;
208	                t++;
209	                continue;
210	            }
211	            // Unknown lowercase word -- error
212	            return -1;
213	        }
214	
215	        // String literal: 'ABC' (single-quoted, for qsvo left argument)
216	        if (line[i] == 39) {
217	            // 39 = single quote
218	            i++;
219	            tok_type[t] = TOK_STRING;
220	            tok_pos[t] = i;  // position of first char
221	            tok_val[t] = i;  // store start of string content
222	            while (line[i] && line[i] != 39) i++;
223	            if (line[i] != 39) return -1;  // unterminated string
224	            i++;  // skip closing quote
225	            t++;
226	            continue;
227	        }
228	
229	        // Uppercase letter: user identifier
230	        if (is_upper(line[i])) {
231	            tok_type[t] = TOK_IDENT;
232	            tok_pos[t] = i;
233	            tok_val[t] = i;  // store start position for name extraction
234	            i++;
235	            while (is_alnum(line[i])) i++;
236	            t++;
237	            continue;
238	        }
239	
240	        // Operators and punctuation
241	        if (line[i] == 43) { tok_type[t] = TOK_PLUS;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
242	        if (line[i] == 45) { tok_type[t] = TOK_MINUS;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
243	        if (line[i] == 42) { tok_type[t] = TOK_STAR;   tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
244	        if (line[i] == 47) { tok_type[t] = TOK_SLASH;  tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
245	        if (line[i] == 40) { tok_type[t] = TOK_LPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
246	        if (line[i] == 41) { tok_type[t] = TOK_RPAREN; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
247	
248	        // Quad: [] (IBM 5100 ASCII convention for ⎕) or bracket indexing [expr]
249	        if (line[i] == 91) {
250	            if (line[i + 1] == 93) {
251	                // [] = quad
252	                tok_type[t] = TOK_QUAD;
253	                tok_pos[t] = i;
254	                tok_val[t] = 0;
255	                t++;
256	                i = i + 2;
257	            } else {
258	                // [ = bracket index open
259	                tok_type[t] = TOK_LBRAK;
260	                tok_pos[t] = i;
261	                tok_val[t] = 0;
262	                t++;
263	                i++;
264	            }
265	            continue;
266	        }
267	        if (line[i] == 93) {
268	            tok_type[t] = TOK_RBRAK;
269	            tok_pos[t] = i;
270	            tok_val[t] = 0;
271	            t++;
272	            i++;
273	            continue;
274	        }
275	
276	        // Assignment: <-
277	        if (line[i] == 60 && line[i + 1] == 45) {
278	            tok_type[t] = TOK_ASSIGN;
279	            tok_pos[t] = i;
280	            tok_val[t] = 0;
281	            t++;
282	            i = i + 2;
283	            continue;
284	        }
285	
286	        // Comparison operators: = != >= <= > <
287	        // 61 '='  33 '!'  62 '>'  60 '<'
288	        if (line[i] == 61) { tok_type[t] = TOK_EQ; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
289	        if (line[i] == 33 && line[i + 1] == 61) { tok_type[t] = TOK_NE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
290	        if (line[i] == 62 && line[i + 1] == 61) { tok_type[t] = TOK_GE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
291	        if (line[i] == 60 && line[i + 1] == 61) { tok_type[t] = TOK_LE; tok_pos[t] = i; tok_val[t] = 0; t++; i = i + 2; continue; }
292	        if (line[i] == 62) { tok_type[t] = TOK_GT; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
293	        if (line[i] == 60) { tok_type[t] = TOK_LT; tok_pos[t] = i; tok_val[t] = 0; t++; i++; continue; }
294	
295	        // Unrecognized character
296	        return -1;
297	    }
298	
299	    // Append EOL sentinel
300	    tok_type[t] = TOK_EOL;
301	    tok_pos[t] = i;
302	    tok_val[t] = 0;
303	    t++;
304	    tok_count = t;
305	    return t;
306	}
307	
308	// ---- Debug: print token list ----
309	// Useful for testing the tokenizer in isolation.
310	void tok_dump(char *line) {
311	    int i = 0;
312	    while (i < tok_count) {
313	        int ty = tok_type[i];
314	        if (ty == TOK_EOL) {
315	            io_print("EOL");
316	        } else if (ty == TOK_NUM) {
317	            io_print("NUM:");
318	            print_int(tok_val[i]);
319	        } else if (ty == TOK_IDENT) {
320	            io_print("ID:");
321	            int p = tok_val[i];
322	            while (is_alnum(line[p])) {
323	                putchar(line[p]);
324	                p++;
325	            }
326	        } else if (ty == TOK_RES) {
327	            io_print("RES:");
328	            int r = tok_val[i];
329	            if (r == RES_RHO)  io_print("rho");
330	            if (r == RES_IOTA) io_print("iota");
331	            if (r == RES_TAKE) io_print("take");
332	            if (r == RES_DROP) io_print("drop");
333	            if (r == RES_REV)  io_print("rev");
334	            if (r == RES_CAT)  io_print("cat");
335	        } else if (ty == TOK_PLUS)   { putchar(43); }
336	          else if (ty == TOK_MINUS)  { putchar(45); }
337	          else if (ty == TOK_STAR)   { putchar(42); }
338	          else if (ty == TOK_SLASH)  { putchar(47); }
339	          else if (ty == TOK_LPAREN) { putchar(40); }
340	          else if (ty == TOK_RPAREN) { putchar(41); }
341	          else if (ty == TOK_ASSIGN) { io_print("<-"); }
342	
343	        if (tok_type[i + 1] != TOK_EOL || ty == TOK_EOL) {
344	            // nothing
345	        }
346	        if (i + 1 < tok_count) putchar(32);
347	        i++;
348	    }
349	    putchar(10);
350	}
