        // Count number of 1s in mask
        int count = 0;
        int i = 0;
        while (i < lsz) {
            if (arr_get(lv, i)) count++;
            i++;
        }

        int r = arr_vector(count);
        if (r < 0) { eval_err = 5; return -1; }

        int ri = 0;
